@using sv_b786e2fc1a3f4322980ac54c1908ebe3.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">
            <span class="badge bg-primary">@WarehouseState.CurrentWarehouseId</span>
            @WarehouseState.CurrentWarehouseName
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger ms-2">@AlertService.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success ms-2">All clear</span>
            }
        </h5>
        <p class="text-body-secondary">
            Polling every 10 seconds. Last check: @_lastRefresh.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private DateTime _lastRefresh = DateTime.Now;
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        // Subscribe to alert changes so we update when ANY component triggers a refresh.
        _alertHandler = () => InvokeAsync(() =>
        {
            _lastRefresh = DateTime.Now;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Subscribe to warehouse changes to update the header text.
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Start polling — stops when this page disposes.
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.StopPolling();
    }
}

